What does this program print?

```cpp
#include <iostream>
#include <memory>

int main() {
    std::unique_ptr<int> a = std::make_unique<int>(99);
    std::unique_ptr<int> b = std::move(a);
    if (!a) std::cout << "a is null\n";
    std::cout << *b << "\n";
    return 0;
}
```

