#include <iostream>
#include <memory>

int main() {
    std::unique_ptr<int> p = std::make_unique<int>(3);
    std::cout << *p << "\n";
    p.reset(); // releases the managed object
    if (!p) std::cout << "p is empty\n";
    return 0;
}
